import sys
from collections import deque
data = open('input.txt').read().split()
results = open('out.txt').read().splitlines()
T = int(data[0]); idx = 1
for t in range(T):
    n, m = int(data[idx]), int(data[idx+1]); idx += 2
    edges = []
    for _ in range(m):
        u, v = int(data[idx]), int(data[idx+1]); edges.append((u,v)); idx += 2
    adj = [[] for _ in range(n)]; indeg = [0]*n
    for u, v in edges:
        adj[u].append(v); indeg[v] += 1
    q = deque(i for i in range(n) if indeg[i] == 0); ind = list(indeg); order = []
    while q:
        u = q.popleft(); order.append(u)
        for v in adj[u]:
            ind[v] -= 1
            if ind[v] == 0: q.append(v)
    has_cycle = len(order) != n
    assert t < len(results), f'case {t}: missing output'
    line = results[t].strip()
    if has_cycle:
        assert line == 'CYCLE', f'case {t}: expected CYCLE got {line!r}'
    else:
        nodes = [int(x) for x in line.split()]
        assert sorted(nodes) == list(range(n)), f'case {t}: bad nodes {nodes}'
        pos = {x: i for i, x in enumerate(nodes)}
        for u, v in edges:
            assert pos[u] < pos[v], f'case {t}: edge {u}->{v} violated by order {nodes}'
print('OK')
